        start_pos = 'I-9',
        description = 'A report has been received regarding the location of an enemy supply train. You are to travel to Ruhotz Silvermines via Grauberg, intercept the caravan, and destroy it.',
        reward = 'Experience Points\nAllied Notes',
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Talk to Hieronymus.\n2. Travel to the Beastmen Ensign at (G-12) in Grauberg.\n   - Party of 3 or greater required.\n3. Once the party leader has selected to enter, you will be transported into Ruhotz Silvermines.\n4. You\'ll start out at (J-7). Head to the intersections at (I-8). The southern path looks like it leads somewhere, but is actually a dead-end. Instead, head north where there will be a few Bronze Quadavs. Wipe them out as you see fit (Sleep to handle the inevitable links is highly reccomended) and head to the west, where you\'ll find stronger Iron Quadavs. Again, defeat these Quadav, and head down the stairs where you\'ll find some Iron Quadavs mixed in with some Darksteel Quadavs.\n5. To complete this operation, you need to meet a minimum requirement of war results, the war results tally is displayed after each kill.\n   - Killing a Bronze Quadav or a Brass Quadav increments your Soldiers count.\n   - Killing a Iron Quadav or a Steel Quadav increments your Enlistees count.\n   - Killing a Darksteel Quadav increments your Officers count.\n6. When the completion requirements are met, "Operation Complete" message will be printed in the logs.\n7. Must exit area using the Twilight Aureola for Hieronymus to acknowledge the mission as successful.\n8. Return and talk to Hieronymus for your reward.',
        notes = 'Can be cleaved quite comfortably with a reasonably geared BLU.\nCampaign Operation becomes available after completing Pit Spider I (B)',
    },
    ['By Light of Fire I (W)'] = {
        id = 354,
        start_npc = 'Emhi Tchaoryo',
        start_zone = 'Windurst Waters (S)',
        start_pos = 'H-9',
        description = 'Reconnaissance has indicated that a Yagudo assault force has set up camp at Ghoyu\'s Reverie. Accompany the mercenaries of the Cobra Unit to the area in question via Fort Karugo-Narugo (I-8). Locate and obliterate the campground.',
        reward = '6609 Experience Points \n8078 Allied Notes',
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. After speaking with Emhi Tchaoryo, proceed to the Beastman Ensign at the borderline of H-8/I-8 in Fort Karugo-Narugo (S) to enter Ghoyu\'s Reverie.\n2. Enter the BCNM and defeat at least 9 of the 15 Yagudos.\n3. The battle is capped at 30 minutes, although you will hardly need all of it.\n4. After defeating the Yagudos, exit the BCNM via the Twilight Aureole.\n5. Only the party leader need have the Ops orders to enter the BCNM.  Anyone from any nation can assist.  Everyone will receive Experience Points upon completion of the BCNM.  Those signed up for this Campaign Ops will receive Allied Notes upon speaking to Emhi Tchaoryo.',
        notes = nil,
    },
    ['Cracking Shells (B)'] = {
        id = 176,
        start_npc = 'Hieronymus',
        start_zone = 'Bastok Markets (S)',
        start_pos = 'E-8',
        description = 'In response to our reclaiming of regions surrounding the capital, Za\'Dha Adamantking has organized his surviving legions to launch a mass counter-offensive from Beadeaux. You are to neutralize this threat by eliminating the Quadav leader.',
        reward = nil,
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = 'Note: This special campaign ops is only available when Beadeaux (S) is under the control of Bastok.\n1. Head to Beadeaux (S) after selecting the mission.\n2. Obtain a Diamond Seal (Key Item).\n   - The key item drops off any of the Quadav\'s in Beadeaux (S) (excluding NM\'s).\n   - It can be obtained when the campaign op isn\'t flagged, so check that you don\'t have it before you begin farming it.\n   - Every member of the party currently in the zone will receive a stone when it drops.\n3. You will also need a Quadav Charm to get to the Qulun Dome area of the zone.\n4. Make your way to the Qulun Dome area (L-8) on Map 2 and examine the Ironbound Gate to enter the battlefield.',
        notes = nil,
    },
