    ['Splitting Heirs (S)'] = {
        id = 6,
        start_npc = 'Rasdinice',
        start_zone = 'Southern San d\'Oria (S)',
        start_pos = 'I-9',
        description = 'In response to our reclaiming of regions surrounding the capital, Darkheir Grradhod has organized his surviving hordes to launch a mass counter-offensive from La Vaule. You are to neutralize this threat by eliminating the Orc leader.',
        reward = nil,
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = 'Note: This special campaign ops is only available when La Vaule (S) is under the control of San d\'Oria.\n1. Head to La Vaule (S) after selecting the mission.\n2. Obtain a Tigris stone (Key Item).\n   - The stone drops off any of the Orcs in La Vaule (S) (excluding NMs).\n   - Every member of the party currently in the zone will receive a stone when it drops.\n   - However, only members with the Op flagged can enter the BCNM.\n3. The entrance to the battlefield is at the Reinforced Gateway at (F-9).\n4. Inside the battlefield, four NM\'s will spawn.\n5. Darkheir Grradhod (SAM) and his three helpers; Gorepledge Rozzbrezz (PLD), Malicearm Razbhobb (MNK), and Slitherword Razghogg (BLM).\n   - Only Darkheir Grradhod has to be defeated to win the fight.\n     - Darkheir Grradhod can use Meikyo Shisui.\n     - He has a unique WS called Tornado Edge which reduces HP by 50%, MP by 50% and reduces TP to 100%.\n     - He has a very high Counter rate.\n     - He is resistant to Sleep spells, however his helpers are not.\n     - If Slitherword Razghogg is alive, Grradhod will have heavy magic resistence.\n     - If Malicearm Razbhobb is alive, Grradhod will have a heavy Attack Bonus and will weaponskill with greater frequency.\n     - If Gorepledge Rozzbrezz is alive, Grradhod will have a heavy Defense Bonus.\n     - His helpers are much weaker, however they will respawn shortly after they are defeated.\n     - The helpers share hate with Darkheir Grradhod.\n6. Once Darkheir Grradhod is defeated, an Armoury Crate will spawn.\n7. Return to Rasdinice to complete the mission.',
        notes = nil,
    },
